#include <bits/stdc++.h>
using namespace std;
int n,m,dist[1003],f[1003],ans;
vector<int> g[1003];
int father(int x){
    return (f[x]==x? x:f[x]=father(f[x]));
}
void merge(int x,int y){
    int fx=father(x),fy=father(y);
    if(fx!=fy)
        f[fy]=fx,ans--;
}
void bfs(int s){
    queue<int> q;
    memset(dist,0,sizeof(dist));
    dist[s]=1,q.push(s);
    while(q.size()){
        int f=q.front(),len=g[f].size();
        q.pop();
        for(int i=0;i<len;i++)
            if(!dist[g[f][i]]){
                dist[g[f][i]]=dist[f]+1,q.push(g[f][i]);
                if(dist[g[f][i]]%2)
                    merge(g[f][i],s);
            }
    }
}
int main(){
    scanf("%d%d",&n,&m);
    ans=n;
    for(int i=1;i<=n;i++)
        f[i]=i;
    for(int i=1;i<=m;i++){
        char op;
        int u,v;
        cin>>op;
        scanf("%d%d",&u,&v);
        if(op=='F')
            merge(u,v);
        else
            g[u].push_back(v),g[v].push_back(u);
    }
    for(int i=1;i<=n;i++)
        bfs(i);
    printf("%d",ans);
    return 0;
}
